[AvaloniaFact]
public async Task LiveTiers_ProviderName_NotRendered()
{
    EnsureNoUserEnv();
    using var repo = TestRepository.Create();
    repo.WriteConfig("dotnet test", []);
    using var r = SeedUserEnv(repo, "HF_TOKEN=hf-abc\n");
    var vm = new MainWindowViewModel { RootPath = repo.Root, EnvironmentAccessor = _env };
    await vm.LoadInitialAsync();
    var window = new MainWindow { DataContext = vm, Width = 1440, Height = 900 };
    window.Show(); Dispatcher.UIThread.RunJobs();
    var dialog = OpenSettings(window);
    var panel = dialog.GetVisualDescendants().OfType<SettingsPanel>().First();
    var itemsControl = panel.FindControl<ItemsControl>("LitTierItems")!;
    Assert.NotNull(itemsControl);

    var dataTemplateGrids = itemsControl.GetVisualDescendants().OfType<Grid>()
        .Where(g => g.ColumnDefinitions.Count == 3).ToList();
    Assert.NotEmpty(dataTemplateGrids);

    // No child in any DataTemplate grid should sit at column 3 (the former ProviderName slot).
    foreach (var grid in dataTemplateGrids)
    {
        foreach (var child in grid.Children)
        {
            var col = Grid.GetColumn(child);
            Assert.NotEqual(3, col);
        }
    }
    dialog.Close(); Dispatcher.UIThread.RunJobs();
}
